var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"늦어서 미안해. 오는 길이 험하더라.","JPN":"遅れてごめんね。道が険しくて。","ENG":"Sorry I’m late. The way over here was brutal.","TWN":"對不起，我來晚了，來的路上很不容易。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"처, 천만에요. 덕분에 아무도 안 다치셔서 다행이에요.","JPN":"と、とんでもないです。おかげさまで誰も怪我しなくてよかったです。","ENG":"D-don't be. I'm just relieved that no one was hurt, thanks to you.","TWN":"哪…哪裡。多虧了你，才沒人受傷。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"오우, 종교학부장이네? 회동 이후로는 처음 보던가?","JPN":"おお、宗教学部長じゃん？　会合以来かな？","ENG":"Ooh! It's the Dean of Religion! Last time we saw each other was at the meeting, no?","TWN":"哇喔，宗教學院院長？會議之後我們是第一次見吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"일단은 그렇다고 해 둘까. 회포를 풀기에는 좋은 자리가 아니긴 해.","JPN":"とりあえずはそういうことにしておくわ。積もる話をするのは場所を移してからにしましょう。","ENG":"Let's leave it at that for now. I don't think this is the time nor place to exchange pleasantries.","TWN":"就算是吧。這裡不是敘舊的好地方。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 그 전에 한 가지 묻고 싶군요.","JPN":"はい。その前に、一つだけお聞きしたいですわね。","ENG":"Agreed. But before we go, I want to ask you something.","TWN":"是的，在那之前，我想先問你一個問題。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저희가 여기 있는 줄은 어떻게 알았죠?","JPN":"どうやって私たちがここにいるとわかったのですか？","ENG":"How did you know we were here?","TWN":"你怎麼知道我們在這裡？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"수도원에 왔을 때 먹은 에그타르트 기억나?","JPN":"修道院に来た時に食べたエッグタルト、覚えてる？","ENG":"Do you remember the egg tarts you ate back at the monastery?","TWN":"還記得你們來修道院的時候吃的蛋撻嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"너희에게 주기 전에 위치를 추적하는 주술을 걸어 뒀거든.","JPN":"あなたたちにあげる前に、位置を追跡する呪術をかけておいたの。","ENG":"Before I gave them to you, I cast a tracking spell on them.","TWN":"在拿給你們之前，我在上面施加了追蹤位置的咒術。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"믿기지가 않아요. 그렇게나 맛있었는데……","JPN":"うそ、あんなに美味しかったのに……","ENG":"No way. But they were so good...","TWN":"不敢相信，那麼好吃的東西……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"응. 주술이라고 해도 실제로는 CRF의 응용이지만.","JPN":"うん。まあ、呪術って言っても、実際にはCRFを応用したものなんだけどね。","ENG":"Good indeed. It’s just another way of using my CRF, rather than an actual spell.","TWN":"嗯，說是咒術，其實也是CRF的應用。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 무슨 이야기인지 이해합니다.","JPN":"いいえ。理解しました。","ENG":"No. I understand.","TWN":"不，我明白你是什麼意思。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 눈도 정보를 얻기 위해 주술적으로 개조된 산물이니까요.","JPN":"その目も情報を手に入れるために呪術的に改造されたものですもの。","ENG":"I remember what you told us about your right eye modified with sorcery to collect intel.","TWN":"因為你的那隻眼睛，也是為了讀取情報，才用咒術改造的產物。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"에그타르트에 대해서는 따지지 않는구나?","JPN":"エッグタルトのことは追及しないのね。","ENG":"Aren't you going to ask about the egg tarts, though?","TWN":"原來你不計較蛋撻啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"눈빛이 달라졌어. 수도원에서 봤을 때와는 확연하게 말이야.","JPN":"目つきが変わったわ。修道院で見た時とは、確実に。","ENG":"Your gaze has changed. It's a far cry from the last time I saw you at the monastery.","TWN":"與來修道院的時候相比，你的眼神變堅定了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 나름대로 각오를 다졌기 때문이겠죠.","JPN":"私なりに覚悟を決めたからでしょう。","ENG":"It would be perhaps because I am now determined.","TWN":"因為我已經做好了心理準備。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여기까지 왔다는 건 돌아갈 수단도 있다는 뜻이겠군요?","JPN":"ここまで来たということは、帰ることもできるという意味ですね。","ENG":"Seeing that you made it all the way here, there must be a way to go back, no?","TWN":"你來到這裡，就說明你也有辦法回去吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아. 그래도 목적지에 따라서는 데려다 줄 수 없어.","JPN":"そうよ。でも、目的地によっては連れて行ってあげられないかな。","ENG":"Correct. However, depending on your destination, I may be unable to take you.","TWN":"沒錯。不過根據目的地不同，我也有可能不能送你們走。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"How so?","TWN":"為什麼呢？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};